=직무: {{ $json.persona }} / 단계: {{ $json.stage }}
제목: {{ $json.title }}
기획 page id: {{ $json.pageId }}

정리된 기획 브리프:
{{ $json.brief }}

기획 단계 질문·답변(이미 결정된 사실):
{{ $json.qa }}

[선행 단계 컨텍스트 — 앞 단계들의 작업 지시서 + 담당자가 제출한 실제 산출물(피그마/PR/문서 링크). 여기 적힌 Figma node id·화면·코드 경로·PR·결정을 그대로 이어받고 다시 찾지 말 것. '담당자 제출 산출물' 링크가 있으면 그 결과물을 최우선 근거로 삼아라]
{{ $json.priorContext }}

parameters.jsCode:
const brief = (($('착수준비 게이트').first().json.output) || {}).brief || '';
const pageId = $('서브태스크 생성').first().json.id;

function inline(s) {
  s = String(s == null ? '' : s);
  const out = [];
  const re = /(\*\*([^*]+)\*\*|`([^`]+)`|\[([^\]]+)\]\(([^)\s]+)\)|(https?:\/\/[^\s)\]]+))/g;
  let last = 0, m;
  while ((m = re.exec(s)) !== null) {
    if (m.index > last) out.push({ type: 'text', text: { content: s.slice(last, m.index) } });
    if (m[2] !== undefined) out.push({ type: 'text', text: { content: m[2] }, annotations: { bold: true } });
    else if (m[3] !== undefined) out.push({ type: 'text', text: { content: m[3] }, annotations: { code: true } });
    else if (m[4] !== undefined) out.push({ type: 'text', text: { content: m[4], link: { url: m[5] } } });
    else if (m[6] !== undefined) out.push({ type: 'text', text: { content: m[6], link: { url: m[6] } } });
    last = re.lastIndex;
  }
  if (last < s.length) out.push({ type: 'text', text: { content: s.slice(last) } });
  if (!out.length) out.push({ type: 'text', text: { content: '' } });
  const split = [];
  out.forEach(function (rt) {
    const c = rt.text.content;
    if (c.length <= 2000) { split.push(rt); return; }
    for (let j = 0; j < c.length; j += 2000) {
      split.push({ type: 'text', text: { content: c.slice(j, j + 2000), link: rt.text.link }, annotations: rt.annotations });
    }
  });
  return split;
}
function cells(line) {
  const parts = line.split('|');
  if (parts.length && parts[0].trim() === '') parts.shift();
  if (parts.length && parts[parts.length - 1].trim() === '') parts.pop();
  return parts.map(function (c) { return c.trim(); });
}

const lines = brief.split('\n');
const blocks = [];
let i = 0;
while (i < lines.length) {
  const line = lines[i];
  if (line.trim().indexOf('```') === 0) {
    const buf = []; i++;
    while (i < lines.length && lines[i].trim().indexOf('```') !== 0) { buf.push(lines[i]); i++; }
    i++;
    let code = buf.join('\n'); if (code.length > 2000) code = code.slice(0, 2000);
    blocks.push({ object: 'block', type: 'code', code: { rich_text: [{ type: 'text', text: { content: code || ' ' } }], language: 'plain text' } });
    continue;
  }
  if (line.trim().indexOf('|') === 0 && i + 1 < lines.length && /^[\s|:-]+$/.test(lines[i + 1]) && lines[i + 1].indexOf('-') !== -1) {
    const header = cells(line);
    const width = header.length;
    const rows = [header];
    i += 2;
    while (i < lines.length && lines[i].trim().indexOf('|') === 0) { rows.push(cells(lines[i])); i++; }
    const children = rows.map(function (r) {
      const c = [];
      for (let k = 0; k < width; k++) c.push(inline(r[k] || ''));
      return { object: 'block', type: 'table_row', table_row: { cells: c } };
    });
    blocks.push({ object: 'block', type: 'table', table: { table_width: width, has_column_header: true, has_row_header: false, children: children } });
    continue;
  }
  const hm = line.match(/^(#{1,6})\s+(.*)$/);
  if (hm) {
    const key = 'heading_' + Math.min(hm[1].length, 3); // Notion 최대 h3 → #### 이상 클램프
    const b = { object: 'block', type: key }; b[key] = { rich_text: inline(hm[2]) };
    blocks.push(b); i++; continue;
  }
  const bm = line.match(/^\s*[-*]\s+(.*)$/);
  if (bm) { blocks.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: inline(bm[1]) } }); i++; continue; }
  const nm = line.match(/^\s*\d+\.\s+(.*)$/);
  if (nm) { blocks.push({ object: 'block', type: 'numbered_list_item', numbered_list_item: { rich_text: inline(nm[1]) } }); i++; continue; }
  if (line.trim() === '---' || line.trim() === '***') { blocks.push({ object: 'block', type: 'divider', divider: {} }); i++; continue; }
  if (line.trim() === '') { i++; continue; }
  blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: inline(line) } });
  i++;
}
if (!blocks.length) blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: '(본문 없음)' } }] } });

// AI 작업 과정 토글(맨 위·접힘) — 💭 사고(모델 서술 process) + 🔧 실제 호출이력(intermediateSteps 검증)
const steps = (($('착수준비 게이트').first().json) || {}).intermediateSteps || [];
const proc = ((($('착수준비 게이트').first().json.output) || {}).process || '').trim();
const TOOLMAP = { '_Hub_': 'Hub 카드 읽기', '_Figma_': 'Figma 조회', 'GitLab_Search': 'GitLab 검색', 'GitLab_File': 'GitLab 파일' };
function clip(v, n) { let s = (typeof v === 'object') ? JSON.stringify(v) : String(v == null ? '' : v); s = s.replace(/\s+/g, ' ').trim(); return s.length > n ? s.slice(0, n) + '…' : s; }
function boldpara(t) { return { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: t }, annotations: { bold: true } }] } }; }
const tchildren = [];
if (proc) {
  tchildren.push(boldpara('💭 사고·판단 (모델이 서술한 과정)'));
  proc.split('\n').forEach(function (ln) {
    if (ln.trim() === '') return;
    let t = ln; if (t.length > 2000) t = t.slice(0, 2000);
    tchildren.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: inline(t) } });
  });
}
if (steps.length) {
  tchildren.push(boldpara('🔧 실제 호출 이력 (검증된 사실, ' + steps.length + '회)'));
  steps.forEach(function (s, idx) {
    const a = s.action || {};
    const tool = TOOLMAP[a.tool] || a.tool || '?';
    const inp = clip(a.toolInput, 300);
    const obs = clip(s.observation, 700);
    tchildren.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: '🔧 ' + (idx + 1) + '. ' + tool }, annotations: { bold: true } }, { type: 'text', text: { content: '  입력: ' + inp } }] } });
    tchildren.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: '← 결과: ' + obs }, annotations: { code: true } }] } });
  });
}
if (tchildren.length) {
  blocks.unshift({ object: 'block', type: 'toggle', toggle: { rich_text: [{ type: 'text', text: { content: '🔍 AI 작업 과정 (사고 + 실제 호출) — 펼쳐보기' } }], children: tchildren.slice(0, 80) } });
}

const groups = [];
for (let g = 0; g < blocks.length; g += 90) groups.push(blocks.slice(g, g + 90));
return groups.map(function (gr) { return { json: { pageId: pageId, children: gr } }; });

